programs._raw:
{
  "name": "North Carolina Seniors Farmers' Market Nutrition Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Household income at or below 185% of the Federal Poverty Level. Examples: $2,322 or less per month for 1-person household; $3,152 or less per month for 2-person household (2024 figures); $2,413/$3,261 cited for 2025 in some regions[1][2][3]. Full table varies by year and household size—check current FPL guidelines via local agency.",
    "asset_limits": "No asset limits mentioned in program details[1][2][3][4][5].",
    "other_requirements": ["Reside in a participating county (not statewide; available in 49-57 of 100 counties)[1][2]", "Not an entitlement program—vouchers not guaranteed even if eligible due to limited funding[1]"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "$50 in vouchers per eligible senior to purchase fresh fruits, vegetables, raw honey, and fresh-cut herbs at certified farmers' markets, roadside stands, or CSAs. Minimum $20, maximum $50 per federal guidelines, redeemable July 1–September 30[1][3][5].",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Fill out NC SFMNP Voucher Interest Form (pre-application to join interest list; notified in June of local agency contacts)[2]", "Contact local agency in participating county for eligibility screening, application, and voucher distribution (varies by county—no central statewide phone/website listed; e.g., NC DHHS Division of Aging leads, partners with county DSS)[3]", "In-person at participating farmers' markets or local agencies (e.g., Mecklenburg County DSS)[3]"],
    "processing_time": "Interest list notifications in June; applications open around then for July start—no specific processing timeline stated[2].",
    "waitlist": "Not guaranteed due to limited funds; interest form acts as pre-waitlist mechanism[1][2].",
    "forms": ["2025 NC SFMNP Voucher Interest Form[2]", "County-specific application via local agency (no statewide form number specified)"],
    "documents": ["Proof of age (60+)", "Proof of residency in participating county", "Proof of household income ≤185% FPL (e.g., pay stubs, tax returns); some agencies may accept proof of enrollment in SNAP/CSFP[5]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to participating counties only (e.g., 49 in 2024, including Chatham, Mecklenburg/Triangle areas; check annual map/list via local agency or NC DHHS)[1][2].",
    "regional_variations": "Administered by local agencies (e.g., county DSS, food councils); different participating markets (e.g., Charlotte Regional Farmers Market, Pittsboro); varying availability and partners by county[1][3].",
    "offices_or_providers": ["Local county agencies (e.g., Mecklenburg County DSS), NC DHHS Division of Aging, certified farmers' markets like Pittsboro, Charlotte Regional[1][3]"]
  },
  "official_source": "https://www.ncdhhs.gov (NC DHHS Division of Aging leads; specific SFMNP page referenced in sources, also check county CES or agr.gov for updates)[1][3]",
  "gotchas": ["Not available in all 100 NC counties—must confirm participating county first[1][2]", "Limited funding means no guarantee even if eligible[1]", "Summer-only (July 1–Sept 30); vouchers unusable outside season or at non-certified vendors[1][3][5]", "Distinct from WIC FMNP (for pregnant/postpartum/children) and SNAP doubling[2][7]", "Income limits based on annual FPL updates—2024/2025 figures differ slightly by source[1][2][3]"],
  "data_shape_notes": "County-restricted (not statewide); fixed $50 voucher regardless of household size; no asset test; pre-application interest form required due to funding limits; varies by local agency administration"
}
